data.while-循环#while 循环:
while(expr) { } 示例
#include using namespace std; int main() { int total{0}; // 初始化 int gradeCounter{1}; while (gradeCounter <= 10) { // while 循环 10 次 cout << "Enter grade: "; int grade; cin >> grade; // 输入 grade total = total + grade; // 加 grade 到 total gradeCounter = gradeCounter + 1; // gradeCounter 次数加 1 } int average{total / 10}; // 求平均 cout << "
Total of all 10 grades is " << total; cout << "
Class average is " << average << "
"; }

